#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);

    if (tx == 0) {
        int i, j, k;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                shadow[i * BLOCK_SIZE + j] =
                    m[(offset + i) * matrix_dim + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = shadow[i * BLOCK_SIZE + j];
                for (k = 0; k < i; k++) {
                    sum -= shadow[i * BLOCK_SIZE + k] *
                           shadow[k * BLOCK_SIZE + j];
                }
                shadow[i * BLOCK_SIZE + j] = sum;
            }

            {
                float elem_1 = 1.0f / shadow[i * BLOCK_SIZE + i];
                for (j = i + 1; j < BLOCK_SIZE; j++) {
                    float sum = shadow[j * BLOCK_SIZE + i];
                    for (k = 0; k < i; k++) {
                        sum -= shadow[j * BLOCK_SIZE + k] *
                               shadow[k * BLOCK_SIZE + i];
                    }
                    shadow[j * BLOCK_SIZE + i] = sum * elem_1;
                }
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + i) * matrix_dim + (offset + j)] =
                    shadow[i * BLOCK_SIZE + j];
            }
        }
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    int tx = (int)get_local_id(0);
    int group = (int)get_group_id(0);
    int blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    if (group >= blocks) {
        return;
    }

    if (tx == 0) {
        int i, j, k;
        int block_off = offset + BLOCK_SIZE * (group + 1);

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i * BLOCK_SIZE + j] =
                    m[(offset + i) * matrix_dim + (offset + j)];
            }
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                float x_2 = 0.0f;
                for (k = 0; k < i; k++) {
                    x_2 += dia[i * BLOCK_SIZE + k] *
                           m[(offset + k) * matrix_dim + (block_off + j)];
                }
                peri_row[i * BLOCK_SIZE + j] =
                    m[(offset + i) * matrix_dim + (block_off + j)] - x_2;
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + i) * matrix_dim + (block_off + j)] =
                    peri_row[i * BLOCK_SIZE + j];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float x_2 = 0.0f;
                for (k = 0; k < j; k++) {
                    x_2 += m[(block_off + i) * matrix_dim + (offset + k)] *
                           dia[k * BLOCK_SIZE + j];
                }
                peri_col[i * BLOCK_SIZE + j] =
                    (m[(block_off + i) * matrix_dim + (offset + j)] - x_2) /
                    dia[j * BLOCK_SIZE + j];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(block_off + i) * matrix_dim + (offset + j)] =
                    peri_col[i * BLOCK_SIZE + j];
            }
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    int lx = (int)get_local_id(0);
    int ly = (int)get_local_id(1);

    if (lx == 0 && ly == 0) {
        int i, j, k;
        int block_row = offset + BLOCK_SIZE * (1 + (int)get_group_id(1));
        int block_col = offset + BLOCK_SIZE * (1 + (int)get_group_id(0));

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_row[i * BLOCK_SIZE + j] =
                    m[(offset + i) * matrix_dim + (block_col + j)];
                peri_col[i * BLOCK_SIZE + j] =
                    m[(block_row + i) * matrix_dim + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < BLOCK_SIZE; k++) {
                    sum += peri_col[i * BLOCK_SIZE + k] *
                           peri_row[k * BLOCK_SIZE + j];
                }
                m[(block_row + i) * matrix_dim + (block_col + j)] -= sum;
            }
        }
    }
}
